import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    n = int(data[0])
    A = list(map(int, data[1:]))

    ans = [A[0]]
    for i in range(n - 1):
        x, y = A[i], A[i + 1]
        if abs(x - y) == 1:
            ans.append(y)
        else:
            if x < y:
                ans.extend(range(x + 1, y))  # x+1 ... y-1
            else:
                ans.extend(range(x - 1, y, -1))  # x-1 ... y+1
            ans.append(y)

    print(*ans)

if __name__ == "__main__":
    solve()
